					annualizedVolatility: 0,
					winRate: 0,
					profitFactor: 0,
					totalTrades: 0,
					sortinoRatio: 0,
					cagr: 0,
				},
				equity_curve: [],
				trade_log: [],
				signals: [],
				config: {
					start_date: startDate,
					end_date: endDate,
					fee_bps: body.fee_bps ?? 10,
					base_dca_amount: body.base_dca_amount ?? 100,
